head.b:skin:
/*
-----------------------------------------------
Master Dy - Custom Blogger Template
Designed and developed by Dymoob
-----------------------------------------------
*/

/* CSS Variables */
:root {
  --accent: #b256f7;
  --accent-dark: #8c3fd4;
  --dark: #151515;
  --text: #2e2e2e;
  --light-bg: #f8f8f8;
}

/* Reset */
html, body, .section, .widget, div, span, applet, object, iframe,
h1, h2, h3, h4, h5, h6, p, blockquote, pre,
a, abbr, acronym, address, big, cite, code,
del, dfn, em, font, img, ins, kbd, q, s, samp,
small, strike, strong, sub, sup, tt, var,
dl, dt, dd, ol, ul, li,
fieldset, form, label, legend,
table, caption, tbody, tfoot, thead, tr, th, td, figure {
  margin: 0;
  padding: 0;
}
html { overflow-x: hidden; }
a { text-decoration: none; color: #000; }
article, aside, details, figcaption, figure,
footer, header, hgroup, menu, nav, section { display: block; }
table { border-collapse: separate; border-spacing: 0; }
caption, th, td { text-align: left; font-weight: normal; }
blockquote:before, blockquote:after, q:before, q:after { content: ""; }
blockquote, q { quotes: "" ""; }
sup { vertical-align: super; font-size: smaller; }
code { font-family: 'Courier New', Courier, monospace; font-size: 12px; color: #272727; }
::selection { background: transparent; text-shadow: #000 0 0 2px; }
::-moz-selection { background: transparent; text-shadow: #000 0 0 2px; }
a img { border: none; }
ol, ul { padding: 0; margin: 0; text-align: left; }
ol li { list-style-type: decimal; padding: 0 0 5px; }
ul li { list-style-type: disc; padding: 0 0 5px; }
ul ul, ol ol { padding: 0; }
#navbar-iframe, .navbar { height: 0px; visibility: hidden; display: none; }
.Attribution, .feed-links,
.post-footer-line.post-footer-line-1,
.post-footer-line.post-footer-line-2,
.post-footer-line.post-footer-line-3 { display: none; }
.item-control { display: none !important; }
h2.date-header, h4.date-header { display: none; margin: 1.5em 0 .5em; }
.quickedit, .home-link { display: none; }

h1, h2, h3, h4, h5, h6 {
  font-family: 'Playfair Display', serif;
  font-weight: 400;
  color: #151515;
}
img { max-width: 100%; vertical-align: middle; border: 0; }
.widget iframe, .widget img { max-width: 100%; }
.status-msg-wrap { display: none; }

/* Preloader */
#preloader {
  position: fixed;
  z-index: 1800;
  top: 0; right: 0; bottom: 0; left: 0;
  width: 100%; height: 100%;
  background: #fff;
}
#loader {
  position: absolute;
  top: calc(50% - 1.25em);
  left: calc(50% - 1.25em);
  width: 2.5em;
  height: 2.5em;
  transform: rotate(165deg);
}
#loader:before, #loader:after {
  content: '';
  position: absolute;
  top: 50%; left: 50%;
  display: block;
  width: 0.5em; height: 0.5em;
  border-radius: 0.25em;
  transform: translate(-50%, -50%);
}
#loader:before { animation: before 2s infinite; }
#loader:after { animation: after 2s infinite; }
@keyframes before {
  0%   { width: 0.5em; box-shadow: 1em -0.5em rgba(245,2,2,.8), -1em 0.5em rgba(163,54,218,.8); }
  35%  { width: 2.5em; box-shadow: 0 -0.5em rgba(245,2,2,.8), 0 0.5em rgba(163,54,218,.8); }
  70%  { width: 0.5em; box-shadow: -1em -0.5em rgba(245,2,2,.8), 1em 0.5em rgba(163,54,218,.8); }
  100% { box-shadow: 1em -0.5em rgba(245,2,2,.8), -1em 0.5em rgba(163,54,218,.8); }
}
@keyframes after {
  0%   { height: 0.5em; box-shadow: 0.5em 1em rgba(49,44,43,.8), -0.5em -1em rgba(136,130,229,.8); }
  35%  { height: 2.5em; box-shadow: 0.5em 0 rgba(49,44,43,.8), -0.5em 0 rgba(136,130,229,.8); }
  70%  { height: 0.5em; box-shadow: 0.5em -1em rgba(49,44,43,.8), -0.5em 1em rgba(136,130,229,.8); }
  100% { box-shadow: 0.5em 1em rgba(49,44,43,.8), -0.5em -1em rgba(136,130,229,.8); }
}

/* Body */
body {
  color: var(--text);
  font-family: Montserrat, sans-serif;
  font-size: 14px;
  font-weight: normal;
  line-height: 21px;
  background: #ffffff;
}

/* Layout */
#outer-wrapper { max-width: 100%; margin: 0 auto; background-color: #FFF; box-shadow: 0 0 5px rgba(0,0,0,.2); }
.row { width: 1170px; }
#content-wrapper { margin: 0 auto; padding: 20px 0 30px; overflow: hidden; }
.item #main-wrapper, .statc_page #main-wrapper { float: left; width: 68%; max-width: 800px; }
.index #main-wrapper, .archive #main-wrapper { float: none; width: 100%; max-width: 100%; }
.item #sidebar-wrapper, .statc_page #sidebar-wrapper { float: right; width: 30%; max-width: 330px; }
.index #sidebar-wrapper, .archive #sidebar-wrapper { display: none; visibility: hidden; height: 0; opacity: 0; }

/* Scrolling Nav */
.scroll-header {
  z-index: 9;
  position: absolute;
  top: 0; left: 0;
  width: 100%;
  padding: 10px 0;
  transition: all .5s;
}
.item .scroll-header, .static_page .scroll-header, .error_page .scroll-header {
  position: static;
  display: flex;
  background: #f5f5f5;
  box-shadow: 0 0 6px 1px rgba(0,0,0,.1);
  padding: 20px 0;
}
.scroll-header.scrolled-header {
  background-color: rgba(30,30,30,.85);
  border-bottom: 1px solid #262626;
  position: fixed;
  top: 0; left: 0; right: 0;
  visibility: visible;
  display: block;
  transition: all .5s;
}
.scroll-head-wrap { margin: 0 auto; }
.item .scroll-header h1, .static_page .scroll-header h1, .error_page .scroll-header h1 { display: block !important; color: #000 !important; }
.item .scroll-header #header img, .static_page .scroll-header #header img, .error_page .scroll-header #header img { display: none !important; }
.item .scroll-header.scrolled-header h1, .static_page .scroll-header.scrolled-header h1, .error_page .scroll-header.scrolled-header h1 { display: none !important; }
.item .scroll-header.scrolled-header #header img, .static_page .scroll-header.scrolled-header #header img, .error_page .scroll-header.scrolled-header #header img { display: block !important; }
.scrollin-logo { float: left; margin: 0; padding: 0; display: inline-block; }
.scrollin-logo .logo-title {
  font-size: 40px;
  font-family: 'Righteous', cursive;
  font-weight: bold;
  padding: 10px 17px;
  display: block;
  color: #fff;
}
.scrolling-menu { float: right; display: inline-block; width: auto; }
.scrolling-menu #nav { list-style: none; margin: 0; padding: 0; z-index: 999; }
.scrolling-menu #nav li { display: inline-block; float: left; line-height: 1; list-style: none; padding: 16px 17px; text-align: left; }
.scrolling-menu #nav li a {
  background: transparent;
  color: #fff;
  display: block;
  font-size: 15px;
  padding: 0 0 8px;
  position: relative;
  text-decoration: none;
  text-transform: uppercase;
  font-weight: bold;
  font-family: Montserrat, sans-serif;
  letter-spacing: 1.3px;
}
.scrolling-menu #nav li a:hover { color: var(--accent); }
.scrolling-menu #nav li.current a { color: var(--accent); }
.scrolling-menu #nav li.current a:before {
  position: absolute;
  bottom: 0; left: 0;
  width: 100%;
  opacity: 1;
  height: 1px;
  content: '';
  transition: all ease .3s;
  background: var(--accent);
}

/* Mobile Menu */
.slicknav_menu { display: none; }
.tm-menu .slicknav_menu { right: 0; display: none; }
.scrolling-menu .slicknav_menu { right: 0; }
.slicknav_menu { padding: 0 10px; position: absolute; z-index: 9; }
.slicknav_menu .slicknav_icon-bar { background-color: #343434; }
.index .slicknav_menu .slicknav_icon-bar { background-color: #fff; }
.slicknav_nav a { padding: 5px 10px; margin: 2px 5px; text-decoration: none; color: #000; font-size: 11px; font-weight: 400; letter-spacing: 2px; text-transform: uppercase; font-family: Montserrat, sans-serif; }
.slicknav_btn { position: relative; display: block; vertical-align: middle; float: right; line-height: 27px; cursor: pointer; height: 27px; }
.slicknav_menu .slicknav_menutxt { display: block; line-height: 1.188em; float: left; }
.slicknav_menu .slicknav_icon { float: left; margin: 0.188em 0 0 0.438em; }
.slicknav_menu .slicknav_no-text { margin: 0; }
.slicknav_menu .slicknav_icon-bar { display: block; width: 1.125em; height: 0.125em; }
.slicknav_btn .slicknav_icon-bar + .slicknav_icon-bar { margin-top: 0.188em; }
.slicknav_nav { clear: both; }
.slicknav_nav ul, .slicknav_nav li { display: block; }
.slicknav_nav .slicknav_arrow { font-size: 0.8em; margin: 0 0 0 0.4em; }
.slicknav_nav .slicknav_item { cursor: pointer; }
.slicknav_nav .slicknav_row { display: block; }
.slicknav_nav a { display: block; }
.slicknav_nav .slicknav_item a, .slicknav_nav .slicknav_parent-link a { display: inline; }
.slicknav_menu:before, .slicknav_menu:after { content: " "; display: table; }
.slicknav_menu:after { clear: both; }
.scroll-header.scrolled-header .slicknav_btn { color: #fff; }
.scroll-header.scrolled-header .slicknav_menu .slicknav_icon-bar { background-color: #fff; }
.slicknav_menu { font-size: 16px; }
.slicknav_btn { margin: 5px 5px 6px; text-decoration: none; border-radius: 4px; }
.slicknav_menu .slicknav_menutxt { color: #FFF; font-weight: bold; text-shadow: 0 1px 3px #000; }
.slicknav_nav { color: #fff; margin: 0; padding: 0; font-size: 0.875em; background: #fff; }
.slicknav_nav, .slicknav_nav ul { list-style: none; overflow: hidden; }
.slicknav_nav ul { padding: 0; margin: 8px 0 0 20px; }
.slicknav_nav .slicknav_row { padding: 5px 10px; margin: 2px 5px; }
.slicknav_nav .slicknav_item a, .slicknav_nav .slicknav_parent-link a { padding: 0; margin: 0; }
.slicknav_nav a:hover { color: var(--accent); }
.slicknav_nav .slicknav_txtnode { margin-left: 15px; }
.slicknav_menu .slicknav_no-text { margin-top: 15px; }
.tm-menu { font-weight: 400; margin: 0; height: 60px; text-align: center; float: right; display: none; width: auto; }
.item .tm-menu, .static_page .tm-menu, .error_page .tm-menu { display: inline-block; }
ul#nav1 { list-style: none; margin: 0; padding: 0; text-align: center; }
#menu .widget { display: none; }
#menu { height: 60px; position: relative; text-align: center; z-index: 15; margin: 0 auto; }
.menu-wrap { margin: 0 auto; position: relative; }
#menu ul > li { position: relative; vertical-align: middle; display: inline-block; padding: 0; margin: 0; }
#menu ul > li:hover > a { color: var(--accent); }
.index #menu ul > li > a { color: #fff; }
#menu ul > li > a { color: #000; font-size: 14px; line-height: 60px; display: inline-block; text-transform: uppercase; text-decoration: none; letter-spacing: 1px; margin: 0; padding: 0 12px; font-family: Montserrat, sans-serif; }
.scroll-header.scrolled-header #menu ul > li > a,
.scroll-header.scrolled-header #header h1 a { color: #fff; }
.scroll-header.scrolled-header #menu ul > li > ul > li > a { color: #000; }
#menu ul > li:first-child > a { padding-left: 0; }
#menu ul > li > ul > li:first-child > a:before,
#menu ul > li > ul > li > ul > li:first-child > a:before { display: none; }
#menu ul > li > ul > li:first-child > a { padding-left: 12px; }
#menu ul > li > ul {
  position: absolute;
  background: #fff;
  box-shadow: 0 7px 7px rgba(0,0,0,.15);
  top: 100%; left: 0;
  min-width: 180px;
  padding: 0; z-index: 99; margin-top: 0;
  visibility: hidden; opacity: 0;
  transform: translate3d(-11px,0,0);
  animation-duration: .5s;
}
#menu ul > li > ul > li > ul { position: absolute; top: 0; left: 180px; width: 180px; background: #fff; z-index: 99; margin: 0; padding: 0; border-left: 1px solid #e5e5e5; visibility: hidden; opacity: 0; transform: translateY(10px); }
#menu ul > li > ul > li { display: block; float: none; text-align: left; position: relative; border-bottom: 1px solid #e5e5e5; border-top: none; }
#menu ul > li > ul > li:hover { background-color: rgba(255,255,255,.03); }
#menu ul > li > ul > li a { font-size: 11px; display: block; color: #000; line-height: 35px; text-transform: uppercase; text-decoration: none; margin: 0; padding: 0 12px; border: 0; }
.index #menu ul > li > ul > li a { color: #000; }
#menu ul > li.parent > a:after { content: '\f107'; font-family: "Font Awesome 6 Free"; font-weight: 900; float: right; margin-left: 5px; }
#menu ul > li:hover > ul,
#menu ul > li > ul > li:hover > ul { opacity: 1; visibility: visible; transform: translateY(0); }
#menu ul > li > ul > li.parent > a:after { content: '\f105'; font-family: "Font Awesome 6 Free"; font-weight: 900; float: right; }

/* Header */
.index #header-wrapper:after, .archive #header-wrapper:after {
  content: '';
  position: absolute;
  bottom: 0; height: 100px; width: 100%;
  background: url(https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEhnMfx7Rhb7F2pEUh3A92lUHrsrJjl5Zt_NnJT7XIMqw0J7TMr_ran10y4i65YNCdQYoJf1ZWkyQ81LcwZWkTKyqDN3ropijGK7kOFPCKDn70niLUkqliFMgOfqERX3h6QG3kBq5A0-Vbw/s1600/header-mask.png) no-repeat center;
  left: 0; right: 0; margin: 0 auto;
  background-size: cover;
}
#header-wrapper {
  text-align: center;
  padding: 0;
  background: url(https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEjwQyPKlsj4vp_quihiSZ4y1dKdt6UOWVuEsvC7btxo71sizZad9XrbHc3OTiAAhOiBjx6aYXedkahWTLEeWIJWUiNIBO-3uvuc_xVH5pn-8cSoY4hEGEIKFC2fY4MVEGab3HQEq1YSA5JGpy1YCnUBsIP3iSE0UQsQm8h7OyXcyuSHgeOBavCPsUiudZ9e/s16000/Foto%20oficial%20Master%20Dy%202026_cover1.jpg) no-repeat center bottom;
  background-attachment: fixed;
  background-size: cover;
  margin-bottom: 10px;
  height: 100vh;
  box-sizing: border-box;
  position: relative;
  width: 100%;
}
.index #header-wrapper { margin-bottom: 0; }
.item .header-logo-desc p, .static_page .header-logo-desc p, .error_page .header-logo-desc p,
.item .top-bar-social #social a, .static_page .top-bar-social #social a, .error_page .top-bar-social #social a { color: #303030; }
.item #header-wrapper, .static_page #header-wrapper, .error_page #header-wrapper {
  background: #fff;
  height: auto;
  border-bottom: 1px solid #eee;
  box-shadow: 0 -2px 19px rgba(0,0,0,.1);
  padding-bottom: 15px;
}
.item #header-wrapper:before, .static_page #header-wrapper:before, .error_page #header-wrapper:before { display: none; }
#header-wrapper:before {
  content: "";
  position: absolute;
  top: 0; left: 0;
  width: 100%; height: 100%;
  opacity: .3;
  background: #343434;
}
#header { padding: 0; }
#header-inner { text-align: center; display: inline-block; }
#header h1 { color: #fff; margin: 0; font-size: 40px; line-height: 1.4em; text-transform: uppercase; letter-spacing: 1px; font-family: 'Righteous', cursive; }
#header .description { display: none; }
.header-text p { color: #fff; margin: 0; font-size: 50px; line-height: 1.4em; text-transform: uppercase; letter-spacing: 1px; font-family: 'Righteous', cursive; }
.header-logo-desc span { font-size: 31px; color: var(--accent); }
.header-logo-desc p {
  display: inline-block;
  white-space: nowrap;
  font-size: 31px;
  line-height: 37px;
  font-weight: 400;
  color: rgb(255,255,255);
  margin: 0 0 0 20px;
  padding-right: 20px;
  opacity: 1;
}
.header-logo-desc { margin: 10px 0 20px; text-transform: uppercase; }
.header-logo-desc .type { position: relative; }
.typed-cursor { font-weight: 300; font-size: 50px; color: var(--accent); opacity: 1; animation: blink 1s infinite; position: absolute; bottom: 0; display: inline-block; }
@keyframes blink { 0%, 100% { opacity: 1; } 50% { opacity: 0; } }
.fenix-head { display: table; width: 100%; height: 110%; }
.fenix-sub-head { margin: 0 auto; display: table-cell; vertical-align: middle; }
.top-bar-social { padding: 0; }
.top-bar-social li { display: inline-block; float: none; padding: 0; margin-right: 5px; }
.top-bar-social li:last-child { margin-right: 0; }
.top-bar-social .widget ul { padding: 0; }
.top-bar-social .LinkList ul { text-align: center; margin: 0; }
.top-bar-social #social a {
  display: block;
  width: 30px; height: 30px;
  line-height: 30px;
  font-size: 12px;
  color: #fff;
  border: 1px solid #e4e4e4;
  border-radius: 100%;
  transition: background 0.3s linear;
}
.top-bar-social #social a:before {
  display: inline-block;
  font-style: normal;
  font-weight: 900;
  -webkit-font-smoothing: antialiased;
}
/* Font Awesome 6 icon classes for social links */
.top-bar-social .facebook:before { font-family: "Font Awesome 6 Brands"; content: "\f09a"; }
.top-bar-social .twitter:before { font-family: "Font Awesome 6 Brands"; content: "\f099"; }
.top-bar-social .instagram:before { font-family: "Font Awesome 6 Brands"; content: "\f16d"; }
.top-bar-social .youtube:before { font-family: "Font Awesome 6 Brands"; content: "\f167"; }
.top-bar-social .soundcloud:before { font-family: "Font Awesome 6 Brands"; content: "\f1be"; }
.top-bar-social .spotify:before { font-family: "Font Awesome 6 Brands"; content: "\f1bc"; }
.top-bar-social .facebook { background: #3b5998; }
.top-bar-social .twitter { background: #00aced; }
.top-bar-social .instagram { background: #c13584; }
.top-bar-social .youtube { background: #cd201f; }
.top-bar-social .soundcloud { background: #ff3300; }
.top-bar-social .spotify { background: #1db954; }
.top-bar-social ul#social a:hover { color: var(--accent); opacity: 1; }

/* Scroll indicator */
.slide-in { font-size: 3.3rem; position: absolute; bottom: 7.2rem; left: 0; display: block; width: 100%; margin: 0; padding: 0; }
.slide-in .pointer {
  position: absolute; top: 50%; left: 50%;
  width: 26px; height: 42px;
  transform: translate(-50%,-50%);
  border: 2px solid #fff;
  border-radius: 26px;
  backface-visibility: hidden;
}
.slide-in .pointer:after {
  position: absolute; top: 5px; left: 50%;
  width: 4px; height: 4px; margin-left: -2px;
  content: '';
  animation: scroll 1.5s -1s cubic-bezier(.68,-.55,.265,1.55) infinite;
  opacity: 1; border-radius: 100%;
  background-color: #fff;
}
@keyframes scroll {
  0%, 20% { transform: translateY(0) scaleY(1) scaleX(1); }
  10% { transform: translateY(0) scaleY(1.2) scaleX(1.2); opacity: 1; }
  to { transform: translateY(20px) scaleY(2.5) scaleX(.5); opacity: .01; }
}

/* Section 1 - Skills */
.sora-special-box { background: #fff; overflow: hidden; margin: 0 auto; padding: 20px 0; }
.special-wrap { margin: 0 auto; }
.special-title { text-align: center; margin-bottom: 35px; }
.special-title h4 { font-size: 35px; line-height: 45px; color: #303030; text-transform: capitalize; }
.special-tiles { width: 100%; box-sizing: border-box; text-align: left; margin-bottom: 20px; }
.special-icons { font-size: 45px; float: left; color: #303030; margin-right: 10px; width: 50px; height: 60px; line-height: 60px; }
.special-heading { font-size: 14px; line-height: 21px; color: #303030; text-transform: capitalize; letter-spacing: 1.5px; margin-bottom: 10px; font-weight: bold; }
.special-text { color: #606060; }
.skills, .skill-details { padding: 15px; width: 50%; float: left; box-sizing: border-box; padding-right: 40px; padding-left: 0; }
.skill-details { float: right; padding-left: 40px; padding-right: 0; }
.skills dt:after { width: 100%; background-color: #e0e0e0; height: 0.5rem; content: ""; display: block; }
.skills dd { background: red; width: 0; height: 0.5rem; position: relative; top: -0.5rem; }
.skills dd.html { background: #F44336; }
.skills dd.css { background: #2196F3; }
.skills dd.jquery { background: #FFCA28; }
.skills dd.scss { background: #F06292; }
.skills dd.javascript { background: #FFA000; }
.skills dd.php { background: #303F9F; }
.skills dd.xml { background: #27ae60; }

/* Section 2 - Works */
.sora-works-box { background: #f1f1f1; overflow: hidden; margin: 0 auto; padding: 20px 0; }
.works-wrap { margin: 0 auto; }
.works-title { text-align: center; margin-bottom: 35px; }
.works-title h4 { font-size: 35px; line-height: 45px; color: #202020; text-transform: capitalize; }
.works-title span { color: #aaa; }
.works-tiles { width: 25%; float: left; padding: 10px; box-sizing: border-box; text-align: center; }
.works-icons { font-size: 45px; display: block; color: var(--accent); margin-bottom: 20px; }
.works-icons li {
  width: 60px; height: 60px;
  background-color: var(--accent);
  border-radius: 50%;
  position: relative; display: inline-block;
  padding: 10px; list-style: none;
  box-shadow: 0 15px 34px rgba(0,0,0,.18);
  transition: all 0.4s ease-in-out;
}
.works-icons li .text { line-height: 60px; font-size: 25px; color: #fff; }
.works-heading { font-size: 18px; line-height: 21px; color: #202020; text-transform: capitalize; letter-spacing: 1.5px; margin-bottom: 10px; font-weight: bold; }
.works-text { margin: 0 0 20px; color: #707070; }

/* Flickity */
.flickity-enabled { position: relative; }
.flickity-enabled:focus { outline: 0; }
.flickity-viewport { overflow: hidden; position: relative; height: 100%; }
.flickity-slider { position: absolute; width: 100%; height: 100%; }
.flickity-enabled.is-draggable { -webkit-user-select: none; user-select: none; }
.flickity-enabled.is-draggable .flickity-viewport { cursor: move; cursor: grab; }
.flickity-enabled.is-draggable .flickity-viewport.is-pointer-down { cursor: grabbing; }
.flickity-prev-next-button { position: absolute; top: 50%; width: 44px; height: 44px; border: none; border-radius: 50%; background: rgba(255,255,255,.75); cursor: pointer; transform: translateY(-50%); }
.flickity-prev-next-button:hover { background: #fff; }
.flickity-prev-next-button:focus { outline: 0; box-shadow: 0 0 0 5px #09F; }
.flickity-prev-next-button:active { opacity: .6; }
.flickity-prev-next-button.previous { left: 10px; }
.flickity-prev-next-button.next { right: 10px; }
.flickity-prev-next-button:disabled { opacity: .3; cursor: auto; }
.flickity-prev-next-button svg { position: absolute; left: 20%; top: 20%; width: 60%; height: 60%; }
.flickity-prev-next-button .arrow { fill: #333; }
.flickity-page-dots { position: absolute; width: 100%; bottom: -25px; padding: 0; margin: 0; list-style: none; text-align: center; line-height: 1; }
.flickity-page-dots .dot { display: inline-block; width: 10px; height: 10px; margin: 0 8px; background: #efefef; border-radius: 50%; opacity: .8; cursor: pointer; padding: 0; }
.flickity-page-dots .dot.is-selected { opacity: 1; }
.main-gallery { background: #000 no-repeat fixed 50% 50%/cover; }
.gallery-cell { width: 100%; }
.testimonial { text-align: center; max-width: 850px; margin: 100px auto 130px auto; padding: 0 20px; }
.testimonial-avatar { width: 100px; border-radius: 50%; }
.testimonial-quote { display: block; font-size: 24px; padding: 10px 0; line-height: 1.4; color: #fff; font-style: italic; font-family: 'Playfair Display', serif; font-weight: 400; }
.testimonial-author { display: block; font-weight: 700; color: var(--accent); }
.flickity-page-dots { bottom: 25px; }
.flickity-page-dots .dot.is-selected { background: var(--accent); }

/* Section 3 - About/Team */
.sora-about-box { background: #f8f8f8; overflow: hidden; margin: 0 auto; padding: 20px 0; }
.about-wrap { margin: 0 auto; }
.about-title { text-align: center; margin-bottom: 35px; }
.about-title h4 { font-size: 35px; line-height: 45px; color: #303030; }
.about-tiles { width: 33.33%; float: left; padding: 10px; box-sizing: border-box; text-align: center; }
.team-img img { transition: all .2s ease-in-out; overflow: hidden; width: 100%; }
.team-member, .team-img { position: relative; overflow: hidden; }
.team-title { margin: 30px 0 7px; }
.overlay { background-color: rgba(20,20,20,.7); position: absolute; top: 0; width: 100%; height: 100%; opacity: 0; transition: all .2s ease-in-out; }
.team-details { opacity: 0; position: absolute; top: 50%; left: 0; padding: 5%; overflow: hidden; width: 100%; z-index: 2; box-sizing: border-box; transition: all .2s ease-in-out; }
.team-details p { color: #fff; }
.team-img:hover .team-details { opacity: 1; margin-top: -80px; }
.team-img:hover .overlay { opacity: 1; }
.socials a { display: inline-block; width: 37px; height: 37px; background-color: transparent; }
.socials i { line-height: 37px; color: #616161; font-size: 14px; width: 37px; height: 37px; border-radius: 50%; text-align: center; transition: all 0.2s linear; }
.team-details .socials i { color: #fff; }
.socials a:hover i { color: #fff; background-color: #355c7d; }

/* Contact Form */
div#sora_blogger_cntct_form {
  padding: 50px 0;
  border-radius: 2px;
  color: #1D1D1D;
  font-size: 15px;
  font-weight: bold;
  position: relative;
  margin: 0 auto;
  overflow: hidden;
}
div#sora_blogger_cntct_form .wrap-me {
  margin: 0;
  display: block;
  max-width: 500px;
  width: 100%;
  float: right;
  box-sizing: border-box;
  background: #000;
  padding: 40px 40px 5px;
}
.contact-title { text-align: center; margin: 25px 0; }
.contact-title h4 { font-size: 35px; line-height: 45px; color: #303030; }
.contact-title span { color: #606060; }
.contact_list_wrapper { text-align: center; }
.contact-list-info { list-style: none; padding: 0; margin: 0; text-align: center; }
.contact_list_wrapper .contact-list-info li { padding: 0 15px; display: inline-block; line-height: 25px; color: #606060; }
.contact_list_wrapper .contact-list-info li i { display: inline; margin-right: 5px; font-size: 15px; vertical-align: -2px; color: #303030; }
.contact_list_wrapper .contact-list-info li p { display: inline; }
input#ContactForm1_contact-form-name,
#ContactForm1_contact-form-email,
#ContactForm1_contact-form-email:hover,
#ContactForm1_contact-form-email:active {
  padding: 5px; margin-top: 4px !important;
  box-shadow: none !important; width: 100%; max-width: 100%;
  background: transparent !important; color: #fff;
  border-color: hsla(0,0%,100%,.15) !important;
  border-width: 0 0 1px 0; line-height: 1em; min-height: 31px;
  margin-bottom: 15px; border-radius: 0;
}
.contact-form-email-message,
.contact-form-email-message:active,
.contact-form-email-message:hover {
  padding: 5px; margin-top: 4px !important;
  box-shadow: none !important; width: 100%; max-width: 100%;
  line-height: 1em; min-height: 80px;
  background: transparent !important; color: #fff;
  border-color: hsla(0,0%,100%,.15) !important;
  border-width: 0 0 1px 0; margin-bottom: 10px; border-radius: 0;
}
#ContactForm1_contact-form-name:focus,
#ContactForm1_contact-form-email:focus,
#ContactForm1_contact-form-email-message:focus {
  outline: none; background: transparent !important; color: #fff;
  border-color: var(--accent) !important; border-width: 0 0 1px 0;
  box-shadow: none !important; transition: all 0.3s ease-in-out !important;
}
.contact-form-button-submit:hover { color: #FFFFFF; background: var(--accent) !important; color: #000 !important; }
.contact-form-button-submit {
  background: transparent; display: table; font-size: 17px;
  margin: 0 !important; border-radius: 0 !important;
  max-width: 100%; width: 100%; min-width: 100%;
  height: 32px; line-height: 0.5em; letter-spacing: 0.5px;
  font-weight: normal; position: relative; cursor: pointer;
  outline: none !important; color: #fff;
  border: 1px solid #fff !important; text-align: center;
  padding: 0 25px; text-transform: capitalize;
  transition: all 300ms ease-in-out;
}
.contact-form-button-submit:focus,
.contact-form-button-submit.focus { border-color: var(--accent); box-shadow: none !important; color: #000 !important; }
.contact-form-success-message,
.contact-form-success-message-with-border { color: #fff !important; margin-top: 55px !important; }
.contact-form-button-submit.disabled,
.contact-form-button-submit.disabled:hover,
.contact-form-button-submit.disabled:active { opacity: 0.9; }
.contact-form-error-message-with-border {
  background: #000; border: 1px solid #5A5A5A; bottom: 0;
  box-shadow: none; color: #FDFDFD; font-size: 15px;
  font-weight: normal; line-height: 35px; margin-left: 0;
  opacity: 1; position: static; text-align: center;
  height: 35px; margin-top: 60px;
}
.contact-form-cross { height: 14px; margin: 5px; vertical-align: -8.5%; float: right; width: 14px; border-radius: 50px; border: 0 !important; cursor: pointer; }
.contact-form-widget { max-width: 100%; }
.contact-form-success-message-with-border {
  font-weight: normal; background-color: #000; border: 1px solid #FFF;
  color: #FFF; line-height: 35px; margin-left: 0; font-size: 13px;
  opacity: 1; position: static; text-align: center; height: 35px; margin-top: 60px;
}
div#sora_blogger_cntct_form span.name-bg,
div#sora_blogger_cntct_form span.email-bg {
  display: inline-block; line-height: 21px; width: 100%;
  color: hsla(0,0%,100%,.6); padding: 3px 0; margin: 0 0 4px;
  box-sizing: border-box; height: 30px; letter-spacing: 1px; font-weight: normal;
}
div#sora_blogger_cntct_form span.message-bg {
  display: inline-block; line-height: 21px; width: 100%;
  color: hsla(0,0%,100%,.6); padding: 3px 0; box-sizing: border-box;
  height: 30px; margin: 0 0 4px; letter-spacing: 1px; font-weight: normal;
}
div#sora_blogger_cntct_form span.send-bg { height: 32px; display: inline-block; float: left; transition: all 0.4s ease-in-out !important; }
div#sora_blogger_cntct_form span.clear-bg { display: none; }
input.contact-form-button.contact-form-button-submit.clear-button:hover { background-color: #E83434 !important; }
div#sora_blogger_cntct_form .clear-button { display: none; }
.map-me { margin: 0; display: block; max-width: 500px; width: 100%; float: left; padding: 40px; box-sizing: border-box; }
.map-me .con-title { font-weight: 700; letter-spacing: -1px; line-height: 48px; color: #000; margin: 0; text-transform: capitalize; }
.map-me .con-text { font-weight: 100; line-height: 24px; color: #555; margin: 0 0 10px; }
.map-me .con-list { list-style-type: none; padding: 0; }
.map-me .con-list li { list-style-type: none; color: #333; line-height: 45px; margin-bottom: 15px; text-transform: capitalize; font-weight: normal; }
.map-me .con-list li i { font-size: 1em; margin-right: 20px; padding: 15px; background: #000; color: #fff; }

/* Sidebar */
.sidebar .widget { margin-bottom: 20px; position: relative; background: #f5f5f5; box-shadow: 0px 2px 6px 0px rgba(0,0,0,.1); }
.sidebar h2 { font-size: 17px; line-height: 27px; color: #000; padding: 7px 15px; font-weight: 400; letter-spacing: 1.5px; text-transform: uppercase; position: relative; text-align: center; background: #f7f7f7; border: 1px solid #f0f0f0; }
.sidebar .widget-content { padding: 10px; box-sizing: border-box; }
.sidebar ul, .sidebar li { list-style-type: none; margin: 0; }

/* Counter */
.counter-box {
  background: url(https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEjUkZ2Q16zeSb2TS56YbFrhxdJNZi8O_uOiDKTdtSfVp1Pb1Nv2njHvN6dc6PghH4C4spiOg0omu_Cy2bG4hy0S9-1pdbrxRxBFxVIGavxOEdUzw4iugX9xbp8sLO_a40S3oEdrD__6O60j7d5x9XYALqlAgrTq_ttFGYrlJgcrUvBEol_DEMrvWzMOO_uM/s16000/Foto%20oficial%20Master%20Dy%202026_concert.jpg) no-repeat;
  background-size: cover;
  background-position: 50% 0;
  overflow: hidden; margin: 0 auto; padding: 170px 0;
  position: relative;
}
.counter-box:before {
  background: rgba(0,0,0,.7);
  content: ""; position: absolute; display: block;
  left: 0; top: 0; width: 100%; height: 100%; bottom: 0;
}
.counter-box-wrap { margin: 0 auto; }
.counter-box-item { width: 25%; float: left; padding: 10px; box-sizing: border-box; text-align: center; color: #fff; position: relative; }
.counter-box-item i { font-size: 24px; }
.counter-sora { color: #fff; font-size: 48px; line-height: 48px; font-weight: 700; margin: 10px 0; transition: all 300ms linear; font-family: 'Righteous', cursive; }
.counter-sora-text { font-size: 14px; text-transform: uppercase; letter-spacing: 3px; color: #fff; }

/* Posts */
.Portfolio-title { text-align: center; margin: 25px 0; }
.Portfolio-title h4 { font-size: 35px; line-height: 45px; color: #303030; text-transform: capitalize; }
.Portfolio-title span { color: #606060; }
article { padding: 0; overflow: hidden; }
.index .post-grid-item, .archive .post-grid-item { width: 25%; float: left; padding-right: 15px; box-sizing: border-box; margin-bottom: 15px; }
.index .post-grid-item:nth-child(4n), .archive .post-grid-item:nth-child(4n) { padding-right: 0; }
.post { display: block; word-wrap: break-word; background: #ffffff; }
.post h1 { color: #0a0a0a; font-size: 28px; font-weight: 400; line-height: 32px; margin: 0 0 10px; }
.post h2 { margin-bottom: 12px; line-height: 37px; font-size: 25px; font-weight: 400; text-transform: capitalize; }
.post h2 a { color: #fff; }
.post h2 { margin: 0 0 10px; padding: 0; }
.retitle h2 { margin: 8px 0; display: block; }
.post-body { margin: 0; padding: 10px; font-size: 14px; line-height: 26px; box-sizing: border-box; text-align: justify; }
.block-image { float: left; width: 100%; height: auto; position: relative; }
.block-image .thumb { width: 100%; height: auto; position: relative; display: block; overflow: hidden; }
.block-image .thumb:before { background: rgba(0,0,0,.5); bottom: 0; content: ""; height: 100%; width: 100%; left: 0; right: 0; margin: 0 auto; position: absolute; opacity: 0; z-index: 3; }
.block-image img { width: 100%; height: 260px; display: block; object-fit: cover; transition: all .3s ease-out !important; }
.block-image:hover .retitle { opacity: 1; }
.block-image:hover .thumb:before { opacity: 1; }
.block-image .retitle { position: absolute; top: 0; text-align: center; display: table; width: 100%; height: 260px; box-sizing: border-box; opacity: 0; z-index: 9; transition: all .3s ease-out !important; }
.block-image .post-retitle { display: table-cell; vertical-align: middle; }
.block-image .post-retitle h2 { position: relative; width: 80%; margin: 0 auto; padding: 20px 10px; }
.post-header { padding: 0 10px 10px; }
.post-meta { color: #bdbdbd; display: block; font-size: 13px; font-weight: 400; line-height: 21px; margin: 0; padding: 0; }
.post-meta a, .post-meta i { color: #CBCBCB; }
.post-timestamp { margin-left: 5px; }
.label-head { margin-left: 5px; }
.label-head a { padding-left: 2px; }
.resumo { margin-top: 10px; color: #919191; }
.resumo span { display: block; margin-bottom: 8px; font-size: 16px; line-height: 31px; }
.post-body img { max-width: 100%; padding: 10px 0; position: relative; margin: 0 auto; }
.second-meta { display: none; }
.comment-link { white-space: normal; }
.ias_trigger { clear: both; text-align: center; }
.ias_trigger a { padding: 8px; color: #fff; background: #222; border-radius: 4px; }
.ias_trigger a:hover { background: var(--accent); }
#blog-pager { clear: both; text-align: center; padding: 15px 0; background: #ffffff; color: #4d4d4d; }
.displaypageNum a, .showpage a, .pagecurrent,
.blog-pager-older-link, .blog-pager-newer-link {
  padding: 5px 13px; margin-right: 8px; color: #fff;
  background-color: #2b2b2b; display: inline-block;
  line-height: 20px; border-radius: 2px; margin-top: 10px;
}
.displaypageNum a:hover, .showpage a:hover, .pagecurrent,
.blog-pager-older-link:hover, .blog-pager-newer-link:hover { background: var(--accent); text-decoration: none; color: #fff; }
.showpageOf { display: none !important; overflow: hidden; }
#blog-pager .pages { margin: 10px 0; border: none; }

/* Share */
.item .post-footer { padding: 0 10px; }
.share-box { position: relative; padding: 10px 0; }
.share-title { border-bottom: 2px solid #777; color: #010101; display: inline-block; padding-bottom: 7px; font-size: 15px; font-weight: 500; position: relative; top: 2px; }
.share-art { float: right; padding: 0; font-size: 13px; font-weight: 400; text-transform: capitalize; }
.share-art a { color: #fff; padding: 3px 8px; margin-left: 4px; border-radius: 2px; display: inline-block; margin-right: 0; background: #010101; }
.share-art a span { display: none; }
.share-art a:hover { color: #fff; }
.share-art .fac-art { background: #3b5998; }
.share-art .fac-art:hover { background: rgba(49,77,145,.7); }
.share-art .twi-art { background: #00acee; }
.share-art .twi-art:hover { background: rgba(7,190,237,.7); }
.share-art .pin-art { background: #CA2127; }
.share-art .pin-art:hover { background: rgba(202,33,39,.7); }
.share-art .lin-art { background: #0077B5; }
.share-art .lin-art:hover { background: rgba(0,119,181,.7); }
.share-art .wat-art { background: #25d266; display: none; }
.share-art .wat-art:hover { background: rgba(37,210,102,.73); }
@media only screen and (max-width: 768px) { .share-art .wat-art { display: inline-block; } }

/* Related Posts */
#related-posts { margin-bottom: 10px; padding: 10px 0; }
.related li { width: 32%; display: inline-block; height: auto; min-height: 184px; float: left; margin-right: 10px; overflow: hidden; position: relative; }
.related li h3 { margin-top: 0; }
.related-thumb { width: 100%; height: 100px; overflow: hidden; border-radius: 2px; }
.related li .related-img { width: 100%; height: 100px; display: block; position: relative; transition: all .3s ease-out !important; }
.related li .related-img:hover { transform: scale(1.1) rotate(-1.5deg) !important; }
.related-title a { font-size: 12px; line-height: 1.4em; padding: 10px 0 0; font-weight: 400; letter-spacing: 1px; color: #010101; display: block; }
.related li:nth-of-type(3n) { margin-right: 0; }
.related .related-tag { display: none; }
.related-overlay { position: absolute; left: 0; top: 0; z-index: 1; width: 100%; height: 100%; background-color: rgba(40,35,40,.05); }
.related-content { display: block; bottom: 0; padding: 0 0 11px; width: 100%; line-height: 1.2em; box-sizing: border-box; z-index: 2; }
.related .related-content .recent-date { font-size: 10px; }
.recent-date:before, .p-date:before { content: '\f017'; font-family: "Font Awesome 6 Free"; margin-right: 5px; }

/* Comments */
.comments { clear: both; margin: 0; color: #48494d; margin-top: 10px; box-sizing: border-box; border-radius: 5px; padding: 30px 30px 20px; background: #FFF; }
.post-feeds .feed-links { display: none; }
iframe.blogger-iframe-colorize, iframe.blogger-comment-from-post { height: 260px !important; background: #fff; }
.comment-form { overflow: hidden; }
.comments h3 { line-height: normal; text-transform: uppercase; color: #333; font-weight: bold; margin: 0 0 20px 0; font-size: 14px; padding: 0; }
h4#comment-post-message { display: none; margin: 0; }
.comments h4 { color: #48494d; border-bottom: 1px solid #efefef; font-size: 16px; padding: 12px 0; margin: 0; font-weight: 700; letter-spacing: 1.5px; text-transform: uppercase; position: relative; text-align: left; }
.comments h4:after { display: inline-block; content: "\f075"; font-family: "Font Awesome 6 Free"; font-weight: 900; font-size: 18px; color: var(--accent); top: 12px; right: 15px; padding: 0; position: absolute; }
.comments .comments-content { font-size: 13px; margin-bottom: 8px; padding: 0; }
.comments .comments-content .comment-thread ol { list-style: none; text-align: left; margin: 13px 0; padding: 0; }
.comments .comments-content .comment-thread ol li { list-style: none; }
.comments .avatar-image-container { background: #fff; border: 1px solid #DDD; overflow: hidden; padding: 0; border-radius: 50%; }
.comments .avatar-image-container img { border-radius: 50%; }
.comments .comment-block { position: relative; background: #fff; padding: 15px; margin-left: 60px; border: 1px solid #efefef; }
.comments .comment-block:before { content: ""; width: 0; height: 0; position: absolute; right: 100%; top: 14px; border-width: 10px; border-style: solid; border-color: transparent #DDD transparent transparent; display: block; }
.comments .comments-content .comment-replies { margin: 8px 0; margin-left: 60px; }
.comments .comments-content .comment-thread:empty { display: none; }
.comments .comment-replybox-single { background: #f0f0f0; padding: 0; margin: 8px 0; margin-left: 60px; }
.comments .comment-replybox-thread { background: #f0f0f0; margin: 8px 0 0 0; padding: 0; }
.comments .comments-content .comment { margin-bottom: 6px; padding: 0; }
.comments .comments-content .comment:first-child, .comments .comments-content .comment:last-child { padding: 0; margin: 0; }
.comments .comment-thread.inline-thread .comment, .comments .comment-thread.inline-thread .comment:last-child { margin: 0 0 5px 30%; }
.comments .comments-content .comment-thread { margin: 0; padding: 0; }
.comments .comments-content .inline-thread { background: #fff; padding: 15px; box-sizing: border-box; margin: 0; }
.comments .comments-content .inline-thread .comment-block { border-color: var(--accent); }
.comments .comments-content .inline-thread .comment-block:before { border-color: transparent var(--accent) transparent transparent; }
.comments .comments-content .user { letter-spacing: 0.5px; font-weight: 600; }
.comments .comments-content .icon.blog-author { display: inline; }
.comments .comments-content .icon.blog-author:after { content: "Author"; background: var(--accent); color: #fff; font-size: 11px; padding: 2px 5px; text-transform: capitalize; font-style: italic; letter-spacing: 0.3px; }
.comment-header { text-transform: uppercase; font-size: 12px; }
.comments .comments-content .datetime { margin-left: 6px; }
.comments .comments-content .datetime a { color: #888; }
.comments .comment .comment-actions a { display: inline-block; color: #333; font-weight: bold; font-size: 10px; line-height: 15px; margin: 4px 8px 0 0; }
.comments .continue a { color: #333; display: inline-block; font-size: 10px; }
.comments .comment .comment-actions a:hover, .comments .continue a:hover { text-decoration: underline; }

/* Footer */
.bot-bar-menu { background-color: #222; padding: 20px 0; overflow: hidden; }
.bot-menu-wrap { margin: 0 auto; position: relative; text-align: center; }
.bot-menu { position: absolute; left: 0; top: 8px; }
.bot-menu h2 { display: none; }
.bot-menu ul { overflow: hidden; list-style: none; padding: 0; margin: 0; }
.bot-menu ul li { float: left; display: inline-block; list-style: none; padding: 0; }
.bot-menu ul li a { padding: 10px 16px; display: block; border: none !important; text-decoration: none; line-height: inherit; font-size: 14px; font-weight: normal; color: #151515; text-transform: uppercase; }
.bot-menu ul li a:hover { color: var(--accent); }
.bottom-bar-social { position: absolute; right: 0; top: 8px; }
.bottom-bar-social li { display: inline; padding: 0; float: left; margin-right: 5px; }
.bottom-bar-social .widget ul { padding: 0; }
.bottom-bar-social .LinkList ul { text-align: center; }
.bottom-bar-social #social a { display: block; font-size: 14px; color: #fff; padding: 10px 5px; }
.bottom-bar-social #social a:before { display: inline-block; font-style: normal; font-weight: 900; -webkit-font-smoothing: antialiased; }
.bottom-bar-social .facebook:before { font-family: "Font Awesome 6 Brands"; content: "\f09a"; }
.bottom-bar-social .twitter:before { font-family: "Font Awesome 6 Brands"; content: "\f099"; }
.bottom-bar-social .instagram:before { font-family: "Font Awesome 6 Brands"; content: "\f16d"; }
.bottom-bar-social .youtube:before { font-family: "Font Awesome 6 Brands"; content: "\f167"; }
.bottom-bar-social ul#social a:hover { color: #151515; opacity: 1; }

/* Footer copyright - MASTER DY own copyright only */
.jugas_footer_copyright { display: inline-block; color: #666; height: 52px; line-height: 52px; font-size: 12px; }
.jugas_footer_copyright a { color: #999; }

/* Widgets */
.sidebar .FollowByEmail > h3.title, .sidebar .FollowByEmail .title-wrap { margin-bottom: 0; }
.FollowByEmail td { width: 100%; float: left; box-sizing: border-box; }
.FollowByEmail .follow-by-email-inner .follow-by-email-submit { margin-left: 0; width: 100%; border-radius: 0; height: 30px; font-size: 11px; color: #fff; background-color: var(--accent); font-family: inherit; text-transform: uppercase; font-weight: 700; letter-spacing: 1px; }
.FollowByEmail .follow-by-email-inner .follow-by-email-submit:hover { opacity: 0.8; }
.FollowByEmail .follow-by-email-inner .follow-by-email-address { padding-left: 10px; height: 30px; border: 1px solid #FFF; margin-bottom: 5px; box-sizing: border-box; font-size: 11px; font-family: inherit; }
.FollowByEmail .follow-by-email-inner .follow-by-email-address:focus { border: 1px solid #FFF; }
.FollowByEmail .widget-content { box-sizing: border-box; padding: 10px; }
.FollowByEmail .widget-content:before { content: "Enter your email address to subscribe to this blog and receive notifications of new posts by email."; font-size: 14px; color: #f2f2f2; line-height: 1.4em; margin-bottom: 5px; display: block; padding: 0 2px; }
.item #ads-home { margin-top: 20px; }
.cloud-label-widget-content { display: inline-block; text-align: left; }
.cloud-label-widget-content .label-size { display: inline-block; float: left; font-size: 16px; line-height: normal; margin: 0 5px 5px 0; opacity: 1; }
.cloud-label-widget-content .label-size a { background: #f8f8f8; color: #878787; float: left; font-weight: 400; line-height: 100%; margin: 0; padding: 7px 8px; text-transform: capitalize; transition: all .6s; border-radius: 2px; }
.lowerbar .cloud-label-widget-content .label-size a { background: #3B3B3B; }
.cloud-label-widget-content .label-size a:hover,
.cloud-label-widget-content .label-size a:active { background: var(--accent); color: #fff; }
.cloud-label-widget-content .label-size .label-count { background: var(--accent); color: #fff; white-space: nowrap; display: inline-block; padding: 6px 8px; margin-left: -3px; line-height: normal; border-radius: 0 2px 2px 0; }
.PopularPosts .item-thumbnail { margin: 0 15px 0 0 !important; width: 90px; height: 65px; float: left; overflow: hidden; position: relative; }
.PopularPosts .item-thumbnail a { position: relative; display: block; overflow: hidden; line-height: 0; }
.PopularPosts ul li img { width: 90px; height: 65px; object-fit: cover; padding: 0; transition: all .3s ease; }
.PopularPosts .widget-content ul li { overflow: hidden; padding: 10px 0; border-top: 1px solid #f2f2f2; }
.PopularPosts ul li a { color: #0a0a0a; font-weight: 400; font-size: 13px; line-height: 1.4em; transition: color .3s; }
.PopularPosts ul li a:hover { color: var(--accent); }
.PopularPosts .item-title { margin: 0 0 4px; padding: 0; line-height: 0; }
.item-snippet { display: none; font-size: 0; padding-top: 0; }
.PopularPosts ul { counter-reset: popularcount; margin: 0; padding: 0; }
.BlogArchive ul li { margin-bottom: 7px !important; padding-bottom: 7px; }
.BlogArchive ul li:last-child { margin-bottom: 0; padding-bottom: 0; border-bottom: none; }
.BlogArchive ul li a { color: #0a0a0a; }
.BlogArchive ul li a:hover { color: var(--accent); }
.BlogArchive .zippy { color: #e74c3c; }
.BlogArchive .post-count-link { font-weight: 700; }
.BlogArchive select { width: 100%; padding: 10px; border-color: #777; }

/* Responsive */
@media only screen and (max-width: 1200px) {
  .row { width: 100%; margin: 0 auto; float: none; padding-left: 10px !important; padding-right: 10px !important; box-sizing: border-box; }
  .index .post-grid-item, .archive .post-grid-item { width: 33.33%; }
  .index .post-grid-item:nth-child(3n), .archive .post-grid-item:nth-child(3n) { padding-right: 0; }
  .index .post-grid-item:nth-child(4n), .archive .post-grid-item:nth-child(4n) { padding-right: 15px; }
}
@media only screen and (max-width: 1100px) {
  div#sora_blogger_cntct_form .wrap-me { max-width: 500px; float: none; clear: both; margin: 0 auto 20px; width: 100%; }
  .map-me { max-width: 500px; float: none; clear: both; margin: 0 auto; width: 100%; }
}
@media only screen and (max-width: 980px) {
  .item #main-wrapper, .statc_page #main-wrapper,
  .item #sidebar-wrapper, .statc_page #sidebar-wrapper { float: none; clear: both; width: 100%; margin: 0 auto; }
  #main-wrapper { max-width: 100%; }
  #sidebar-wrapper { padding-top: 20px; }
  #nav1, #nav { display: none; }
  .slicknav_menu { display: block; }
  .item .tm-menu .slicknav_menu, .static_page .tm-menu .slicknav_menu, .error_page { display: block; }
  .tm-menu, #menu { height: auto; }
  .item .tm-menu, .static_page .tm-menu, .error_page .tm-menu { float: none; display: block; }
}
@media screen and (max-width: 880px) {
  .index .post-grid-item, .archive .post-grid-item { width: 32%; }
  .home #header-wrapper { margin-bottom: 10px; }
  .item #content-wrapper { padding: 0 0 30px; }
  .skills, .skill-details { width: 100%; float: none; padding: 20px; clear: both; }
}
@media only screen and (max-width: 768px) {
  .counter-box-item, .works-tiles { width: 50%; }
  #header h1 { font-size: 50px; }
  .index .post-grid-item, .archive .post-grid-item { width: 100%; padding-right: 0; }
  .top-bar-social { float: none; width: 100%; clear: both; overflow: hidden; }
  .top-bar-social li { display: inline-block; float: none; }
  .flickity-prev-next-button { display: none; }
  .bot-menu, .bottom-bar-social { float: none; width: 100%; clear: both; overflow: hidden; position: static; }
  .bot-menu ul { text-align: center; }
  .bot-menu ul li { float: none; }
  .bottom-bar-social li { float: none; display: inline-block; }
  .related li { width: 31%; }
  .share-art span { display: none; }
  #header { padding: 10px 0 0; }
}
@media only screen and (max-width: 767px) {
  #header { padding: 0; }
  #header h1 { font-size: 30px; }
  .header-text p { font-size: 30px; }
  .slide-in { display: none; }
}
@media only screen and (max-width: 480px) {
  .slide-in { display: block; }
  .special-tiles, .works-tiles, .about-tiles, .counter-box-item { width: 100%; }
  #header h1 { font-size: 30px; }
  .header-text p { font-size: 20px; }
  .header-logo-desc span, .header-logo-desc p { font-size: 16px; }
  .index .post h2, .archive .post h2 { line-height: 34px; font-size: 23px; }
  h1.post-title { font-size: 22px; margin-bottom: 10px; }
  #sidebar-wrapper { max-width: 100%; }
  .share-title { display: none; }
  .share-art { float: none; text-align: center; }
  .related li { width: 100%; margin: 0 auto; }
}
@media only screen and (max-width: 360px) {
  .header-logo-desc p { font-size: 100%; }
  #header h1 { font-size: 250%; }
}
@media only screen and (max-width: 300px) {
  #sidebar-wrapper { display: none; }
  .archive .post h2, .index .post h2, #first-post .post h2 { line-height: 29px !important; font-size: 15px !important; }
  article { overflow: hidden; }
  #blog-pager { padding: 0; margin: 0; }
  .share-art, .share-box .post-author { float: none !important; margin: 0 auto; text-align: center; clear: both; }
  .read-more-wrap, .post-labels { float: none !important; clear: both; display: block; text-align: center; }
  h1.post-title { font-size: 17px; }
  .share-box { overflow: hidden; }
  .top-bar-social #social a { width: 24px; height: 24px; line-height: 24px; }
  .second-meta .share-art a { padding: 5px; }
  .comments .avatar-image-container { display: none; }
  .comments .comment-block { margin-left: 0 !important; position: relative; }
}

head.b:template-skin:
#layout #preloader, #layout .scrolling-menu { display: none; }
#layout .sora-contact-widget { display: none; }
body#layout #outer-wrapper { padding: 0; width: 800px; }
body#layout .section h4 { color: #333!important; text-align:center; text-transform:uppercase; letter-spacing:1.5px; }
body#layout .tm-menu, body#layout #menu { height: auto; position:static; }
body#layout #menu .widget { display: block; visibility:visible; }
body#layout #header-wrapper { height: auto; }
body#layout #content-wrapper { margin: 0 auto; padding:0; }
body#layout #main-wrapper { float: left; width: 70%; margin: 0; padding: 0; }
body#layout #sidebar-wrapper { float: right; width: 30%; margin: 0; padding: 0; display: block; visibility: visible; height: auto; opacity: 1; }
body#layout #sidebar-wrapper .section { background-color: #8e7cc3 !important; border: 1px solid #fff; }
body#layout #sidebar-wrapper .section h4 { color:#fff; }
body#layout .sora-special-box, body#layout .sora-works-box, body#layout .sora-about-box, body#layout .insta-wrap, body#layout .Portfolio-title { display:none; }
body#layout .jugas_footer_copyright { display:none; }

